function Counter() {
  const [count, setCount] = useState(0);
  const click = () => {
    count = count + 1;
    setCount(count);
  };
  return <button onClick={click}>{count}</button>;
}

function Toggle() {
  const [active, setActive] = useState(false);
  setActive(!active);
  return <button>State: {active ? 'On' : 'Off'}</button>;
}

